parameters.jsCode:
// Parse Incoming (UPDATED for responseStyle + SlideChat support)

const raw = $input.first()?.json ?? {};

// Normalize body safely
let body = raw;

if (raw.body) {
  if (typeof raw.body === 'string') {
    try {
      body = JSON.parse(raw.body);
    } catch (e) {
      body = raw.body;
    }
  } else if (typeof raw.body === 'object' && raw.body !== null) {
    body = raw.body;
  }
}

const bodyObj =
  typeof body === 'object' && body !== null && !Array.isArray(body) ? body : {};

// Extract mode
const mode = (bodyObj.mode || raw.mode || 'auto').toString().toLowerCase();

// Accept queries from multiple possible fields
const query = (
  bodyObj.query ||
  bodyObj.chatInput ||
  raw.chatInput ||
  bodyObj.message ||
  raw.message ||
  ''
).toString();

// Capture sessionId
const sessionId = (bodyObj.sessionId || raw.sessionId || '').toString();

// NEW: response style normalization
const allowedStyles = new Set(['explain', 'exam_focus', 'worked_example']);
const responseStyleRaw = (
  bodyObj.responseStyle ||
  raw.responseStyle ||
  ''
).toString().toLowerCase().trim();

const responseStyle = allowedStyles.has(responseStyleRaw)
  ? responseStyleRaw
  : 'explain';

const styleInstructions = {
  explain:
    'Teach clearly for understanding. Prefer plain explanation first. Use a table or diagram only when it helps.',
  exam_focus:
    'Answer like an ELEC3120 revision tutor. Be concise, emphasize likely exam traps, and include exam-oriented phrasing when helpful.',
  worked_example:
    'Give one concrete worked example. For calculation or process questions, prefer a step-by-step solution.',
};

const styleInstruction = styleInstructions[responseStyle];

// SlideChat fields
const isSlideChat = Boolean(bodyObj.isSlideChat);
const slideContext = bodyObj.slideContext || null;

// Detect attachments
let attachments = [];
if (Array.isArray(bodyObj.attachments)) {
  attachments = bodyObj.attachments.filter(Boolean);
} else if (typeof bodyObj.attachment === 'string') {
  attachments = [bodyObj.attachment];
}

const hasAttachments = attachments.length > 0;

// Return items
if (!hasAttachments) {
  return [
    {
      json: {
        query,
        sessionId,
        mode,
        responseStyle,
        styleInstruction,
        hasAttachments,
        attachments: [],
        attachmentIndex: null,
        attachmentCount: 0,
        isSlideChat,
        slideContext,
      },
    },
  ];
}

// Attachments exist - expand to multiple items
return attachments.map((url, index) => ({
  json: {
    query,
    sessionId,
    mode,
    responseStyle,
    styleInstruction,
    hasAttachments: true,
    attachmentUrl: url,
    fileName:
      typeof url === 'string'
        ? url.split('/').pop() || `file_${index}`
        : `file_${index}`,
    attachmentIndex: index,
    attachmentCount: attachments.length,
    isSlideChat,
    slideContext,
  },
}));

