parameters.jsCode:
const items = $input.all();

let combinedMarkdown = '';
const attachmentContexts = [];

for (const it of items) {
  const idx = it.json?.attachmentIndex ?? null;
  const fileName = it.json?.fileName ?? null;

  const pages = it.json?.pages || [];
  let md = '';

  for (const p of pages) {
    if (typeof p.markdown === 'string' && p.markdown.trim()) {
      md += p.markdown + '\n\n';
    }
  }

  md = md.trim();
  if (md) {
    attachmentContexts.push({
      attachmentIndex: idx,
      fileName,
      markdown: md,
    });

    combinedMarkdown += `Attachment ${idx}: ${fileName || ''}\n${md}\n\n`;
  }
}

const first = items[0]?.json || {};

return [
  {
    json: {
      query: first.query || '',
      sessionId: first.sessionId || '',
      mode: (first.mode || 'auto').toString().toLowerCase(),
      responseStyle: first.responseStyle || 'explain',
      styleInstruction:
        first.styleInstruction ||
        'Teach clearly for understanding. Prefer plain explanation first. Use a table or diagram only when it helps.',
      isSlideChat: Boolean(first.isSlideChat),
      slideContext: first.slideContext || null,
      pdfContext: combinedMarkdown.trim(),
      attachmentContexts: attachmentContexts
        .filter(Boolean)
        .sort((a, b) => (a.attachmentIndex ?? 0) - (b.attachmentIndex ?? 0)),
      hasContext: combinedMarkdown.trim().length > 0,
    },
  },
];

const item = $input.first().json;

return [
  {
    json: {
      query: item.query || '',
      sessionId: item.sessionId || '',
      mode: item.mode || 'auto',
      responseStyle: item.responseStyle || 'explain',
      styleInstruction:
        item.styleInstruction ||
        'Teach clearly for understanding. Prefer plain explanation first. Use a table or diagram only when it helps.',
      isSlideChat: Boolean(item.isSlideChat),
      slideContext: item.slideContext || null,
      pdfContext: item.pdfContext || '',
      attachmentContexts: Array.isArray(item.attachmentContexts)
        ? item.attachmentContexts
        : [],
      hasContext: Boolean(item.pdfContext && item.pdfContext.length > 0),
    },
  },
];

