parameters.jsCode:
const rawText = $input.item.json.text || '';

// Normalize line breaks and whitespace
const clean = (s) => s.trim().replace(/\s+/g, ' ');

// Split into lines for easier parsing
const lines = rawText.split('\n').map(l => l.trim()).filter(l => l !== '');

let questions = [];
let currentSection = '';
let currentQuestion = null;

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];

  // Detect section headers like 'A Warmup', 'B HTTP', etc.
  const sectionMatch = line.match(/^([A-Z])\s+(.+)$/);
  if (sectionMatch) {
    currentSection = `${sectionMatch[1]} ${sectionMatch[2]}`;
    continue;
  }

  // Detect point-based questions: (2 pts) ...
  const questionMatch = line.match(/^\((\d+)\s*pts?\)\s*(.*)/i);
  if (questionMatch) {
    // Finalize previous question if exists
    if (currentQuestion) questions.push(currentQuestion);

    currentQuestion = {
      section: currentSection,
      points: parseInt(questionMatch[1], 10),
      question_text: clean(questionMatch[2]),
      options: {},
      correct_answer_label: null,
      metadata: {}
    };
    continue;
  }

  // Detect options: A. ..., B. ..., etc.
  const optionMatch = line.match(/^([A-D])\.\s*(.+)$/);
  if (optionMatch && currentQuestion) {
    currentQuestion.options[optionMatch[1]] = clean(optionMatch[2]);
    continue;
  }

  // If line doesn't match any pattern and we have a current question,
  // it might be a continuation (e.g., multi-line question). Append to question_text.
  if (currentQuestion && !line.match(/^[A-D]\.|^[0-9]+\.|^Answer:/)) {
    currentQuestion.question_text += ' ' + clean(line);
  }
}

// Push last question
if (currentQuestion) questions.push(currentQuestion);

// Output as n8n items
return questions.map(q => ({
  json: {
    section: q.section,
    question_text: q.question_text,
    options: Object.keys(q.options).length > 0 ? JSON.stringify(Object.entries(q.options).map(([k, v]) => `${k}. ${v}`)) : null,
    correct_answer_label: q.correct_answer_label,
    points: q.points,
    metadata: JSON.stringify(q.metadata)
  }
}));

const base = $input.first().json;

let finalContext = '';
let sourcesForUser = '';

if (base.hasContext && base.pdfContext) {
  finalContext = base.pdfContext;
  sourcesForUser = 'Uploaded attachments (OCR)';
} else {
  finalContext = '';
  sourcesForUser = 'Lecture notes / Textbook via RAG';
}

return [
  {
    json: {
      query: base.query,
      mode: base.mode,
      sessionId: base.sessionId,
      responseStyle: base.responseStyle || 'explain',
      styleInstruction:
        base.styleInstruction ||
        'Teach clearly for understanding. Prefer plain explanation first. Use a table or diagram only when it helps.',
      isSlideChat: Boolean(base.isSlideChat),
      slideContext: base.slideContext || null,
      finalContext,
      hasContext: base.hasContext,
      sourcesForUser,
    },
  },
];

