  if (raw.mcqs || raw.longForm || raw.metadata) {
    return formatOutput(raw, raw);
  }
  throw new Error(`No JSON brackets found. Preview: ${output.substring(0, 100)}...`);
}

function robustRepair(jsonStr) {
  let inString = false;
  let isEscaped = false;
  let result = '';

  for (let i = 0; i < jsonStr.length; i++) {
    const char = jsonStr[i];

    if (inString) {
      if (isEscaped) {
        result += char;
        isEscaped = false;
      } else {
        if (char === '\\') {
          result += char;
          isEscaped = true;
        } else if (char === '"') {
          inString = false;
          result += char;
        } else if (char === '\n') {
          result += '\\n';
        } else if (char === '\r') {
          // drop carriage returns inside strings
        } else if (char === '\t') {
          result += '\\t';
        } else {
          result += char;
        }
      }
    } else {
      if (char === '"') {
        inString = true;
      }
      result += char;
    }
  }

  return result
    .replace(/,\s*([\]}])/g, '$1')
    .replace(/}\s*{/g, '},{');
}

