  const item = incomingItems[incomingIndex];
  const preparedJob = preparedJobs[incomingIndex];
  const index =
    typeof item.json?.questionIndex === 'number'
      ? item.json.questionIndex
      : preparedJob?.questionIndex;

  if (typeof index !== 'number') continue;

  const diagramSource = normalizeDiagramSource(preparedJob?.diagramSource);
  const fallbackText =
    item.json?.diagramFallbackText ||
    preparedJob?.diagramFallbackText ||
    (diagramSource ? 'Diagram source:\n' + diagramSource : null);

  const rawPayload = readRendererPayload(item);
  const svg = normalizeSvg(rawPayload);

  if (!svg) {
    diagramAssetMap.set(index, {
      diagramSource,
      diagramSvg: null,
      diagramDataUri: null,
      diagramFallbackText: fallbackText,
      diagramRenderError: summarizeRenderFailure(rawPayload),
    });
    continue;
  }

  diagramAssetMap.set(index, {
    diagramSource,
    diagramSvg: svg,
    diagramDataUri: 'data:image/svg+xml;base64,' + Buffer.from(svg, 'utf-8').toString('base64'),
    diagramFallbackText: fallbackText,
    diagramRenderError: null,
  });
}

