const minSubParts =
  Number(req.variation?.difficultyStructure?.minSubParts ?? (req.mode === 'exam_simulation' ? 3 : 0)) || 0;

const issues = [];
const autofixes = [];

function addIssue(message) {
  issues.push(message);
}

function addAutofix(message) {
  autofixes.push(message);
}

function isNonEmptyString(value) {
  return typeof value === 'string' && value.trim().length > 0;
}

function expectedOptionCount(question) {
  return Array.isArray(question.options) ? question.options.length : 0;
}

function normalizeMermaidRoot(diagram) {
  if (!isNonEmptyString(diagram)) return '';
  return diagram
    .trim()
    .replace(/^```(?:mermaid)?\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
}

function isValidMermaidRoot(diagram) {
  const normalized = normalizeMermaidRoot(diagram);
  return /^(graph\s+(?:LR|RL|TB|TD|BT)|flowchart\s+(?:LR|RL|TB|TD|BT)|sequenceDiagram|classDiagram|stateDiagram)/.test(normalized);
}

function hasSubPartMarkersInQuestion(text) {
  return /\(\s*[a-zA-Z]\s*\)|^\s*[a-zA-Z][).]\s+/m.test(text || '');
}

function containsAnswerLeak(text) {
  return /(correct answer|the answer is|therefore the answer is|thus the answer is|this proves that the answer is)/i.test(text || '');
}

function promptTextFor(question) {
  return [
    question.question,
    ...(Array.isArray(question.sub_parts) ? question.sub_parts.map((part) => part.text) : []),
  ].join(' ');
}

function isTcpFillInPrompt(text) {
  return /fill in|seq\/ack|sequence number|acknowledgment number/i.test(text || '');
}

function diagramRevealsSeqAck(diagram) {
  return /\bSeq\s*=\s*[^?\s,\n][^,\n]*|\bAck\s*=\s*[^?\s,\n][^,\n]*/i.test(diagram || '');
}

function redactTcpAnswerValues(diagram) {
  if (!isNonEmptyString(diagram)) return diagram;
  return diagram
    .replace(/\bSeq\s*=\s*[^,\n]+/gi, 'Seq=?')
    .replace(/\bAck\s*=\s*[^,\n]+/gi, 'Ack=?');
}

function isSymmetricTopologyPrompt(text) {
  return /symmetric topology|bidirectional links?|links in both directions|undirected topology|two-way links?/i.test(text || '');
}

function normalizeSymmetricLinks(diagram) {
  if (!isNonEmptyString(diagram)) return diagram;
  return diagram
    .replace(/-->/g, '---')
    .replace(/==>/g, '===')
    .replace(/-\.->/g, '-.-');
}

function hasUndirectedLinks(diagram) {
  return /---|===|-\.-/.test(diagram || '');
}

function getDirectedPairs(diagram) {
  const pairs = [];

  for (const line of String(diagram || '').split('\n')) {
    const match = line.match(/([A-Za-z0-9_]+).*?(-->|==>|-\.->).*?([A-Za-z0-9_]+)/);
    if (match) {
      pairs.push([match[1], match[3]]);
    }
  }

  return pairs;
}

function isSymmetricDiagram(diagram) {
  if (!isNonEmptyString(diagram)) return false;
  if (hasUndirectedLinks(diagram)) return true;

  const pairs = getDirectedPairs(diagram);
  if (pairs.length === 0) return false;

  const pairSet = new Set(pairs.map(([from, to]) => `${from}->${to}`));
  return pairs.every(([from, to]) => pairSet.has(`${to}->${from}`));
}

function getDiagramFamily(diagram) {
  const mermaidRoot = normalizeMermaidRoot(diagram);

  if (/^sequenceDiagram\b/.test(mermaidRoot)) return 'sequence';
  if (/^(graph|flowchart)\s+/.test(mermaidRoot)) return 'graph';
  return 'other';
}

function validateSequentialNumbers(items, startAt, label) {
  items.forEach((item, index) => {
    const expected = startAt + index;
    if (Number(item.number) !== expected) {
      addIssue(`${label} ${index + 1} should have number ${expected} but received ${item.number}.`);
    }
  });
}

function isValidTableData(tableData) {
  return !!(
    tableData &&
    Array.isArray(tableData.columns) &&
    tableData.columns.length > 0 &&
    Array.isArray(tableData.rows) &&
    tableData.rows.length > 0
  );
}

