  const questionText = question.question || '';

  if (!isNonEmptyString(question.question)) {
    addIssue(`${label} is missing question text.`);
  }

  if (Array.isArray(question.sub_parts) && question.sub_parts.length > 0) {
    addIssue(`${label} looks like a long-form question but is inside mcqs.`);
  }

  if (!Array.isArray(question.options) || question.options.length < 4) {
    addIssue(`${label} must have at least 4 options.`);
  }

  if (!isNonEmptyString(question.correct_answer)) {
    addIssue(`${label} is missing correct_answer.`);
  } else {
    const letter = question.correct_answer.trim().toUpperCase();
    const optionIndex = letter.charCodeAt(0) - 65;
    if (optionIndex < 0 || optionIndex >= expectedOptionCount(question)) {
      addIssue(`${label} has a correct_answer that does not match its options.`);
    }
  }

  if (typeof question.marks !== 'number' || question.marks <= 0) {
    addIssue(`${label} must have a positive numeric marks value.`);
  }

  if (containsAnswerLeak(questionText)) {
    addIssue(`${label} question text appears to reveal the answer.`);
  }

  (Array.isArray(question.options) ? question.options : []).forEach((option, optionIndex) => {
    if (!isNonEmptyString(option)) {
      addIssue(`${label} option ${optionIndex + 1} is empty.`);
    }
    if (containsAnswerLeak(option)) {
      addIssue(`${label} option ${optionIndex + 1} appears to reveal the answer.`);
    }
  });
});

longForm.forEach((question, index) => {
  const label = `Long-form ${index + 1}`;
  const blueprintItem = blueprint[index] || null;
  const requiredDiagram = blueprintItem?.requiredDiagram || 'none';
  const questionFormat = blueprintItem?.questionFormat || 'text';
  const promptText = promptTextFor(question);

  if (!isNonEmptyString(question.question)) {
    addIssue(`${label} is missing scenario text.`);
  }

  if (hasSubPartMarkersInQuestion(question.question)) {
    addIssue(`${label} has sub-part markers inside the question field. Put them only in sub_parts.`);
  }

  if (containsAnswerLeak(question.question)) {
    addIssue(`${label} question text appears to reveal the answer.`);
  }

  if (!Array.isArray(question.sub_parts) || question.sub_parts.length === 0) {
    addIssue(`${label} must include at least one sub-part.`);
  } else if (question.sub_parts.length < minSubParts) {
    addIssue(`${label} must include at least ${minSubParts} sub-parts for this exam structure.`);
  }

  (Array.isArray(question.sub_parts) ? question.sub_parts : []).forEach((part, partIndex) => {
    if (!isNonEmptyString(part.label)) {
      addIssue(`${label} sub-part ${partIndex + 1} is missing a label.`);
    }
    if (!isNonEmptyString(part.text)) {
      addIssue(`${label} sub-part ${partIndex + 1} is missing text.`);
    }
    if (containsAnswerLeak(part.text)) {
      addIssue(`${label} sub-part ${partIndex + 1} appears to reveal the answer.`);
    }
    if (typeof part.marks !== 'number' || part.marks < 0) {
      addIssue(`${label} sub-part ${partIndex + 1} must have a non-negative numeric marks value.`);
    }
  });

  if (question.diagram !== null && question.diagram !== undefined && typeof question.diagram !== 'string') {
    addIssue(`${label} diagram must be either null or a string.`);
  }

  if (typeof question.diagram === 'string') {
    question.diagram = question.diagram.trim();
  }

  if (isTcpFillInPrompt(promptText) && diagramRevealsSeqAck(question.diagram)) {
    const redactedDiagram = redactTcpAnswerValues(question.diagram);
    if (redactedDiagram !== question.diagram) {
      question.diagram = redactedDiagram;
      addAutofix(`${label}: redacted Seq/Ack values from the student-facing diagram.`);
    }
  }

  const hasDiagram = isNonEmptyString(question.diagram);
  const mentionsDiagram = /refer to the diagram below\./i.test(question.question || '');
  const mermaidRoot = normalizeMermaidRoot(question.diagram);
  const diagramFamily = getDiagramFamily(question.diagram);

  if (
    diagramFamily === 'graph' &&
    isSymmetricTopologyPrompt(promptText) &&
    isNonEmptyString(question.diagram) &&
    !isSymmetricDiagram(question.diagram)
  ) {
    const normalizedDiagram = normalizeSymmetricLinks(question.diagram);
    if (normalizedDiagram !== question.diagram) {
      question.diagram = normalizedDiagram;
      addAutofix(`${label}: converted a symmetric topology diagram to undirected links.`);
    }
  }

  if (requiredDiagram !== 'none' && !hasDiagram) {
    addIssue(`${label} is missing required diagram content for blueprint type "${requiredDiagram}".`);
  }

  if (requiredDiagram === 'none' && hasDiagram) {
    addIssue(`${label} should not include a diagram because the blueprint says requiredDiagram = "none".`);
  }

  if (mentionsDiagram && !hasDiagram) {
    addIssue(`${label} says "Refer to the diagram below." but diagram is empty.`);
  }

  if (!mentionsDiagram && hasDiagram) {
    const normalizedQuestion = String(question.question || '').trim();
    question.question = `${normalizedQuestion}${normalizedQuestion.endsWith('.') ? '' : '.'} Refer to the diagram below.`.trim();
    addAutofix(`${label}: appended "Refer to the diagram below." to match the included diagram.`);
  }

  if (hasDiagram && !isValidMermaidRoot(question.diagram)) {
    addIssue(`${label} diagram is present but does not start with a valid Mermaid root.`);
  }

  if (requiredDiagram === 'sequenceDiagram' && hasDiagram && !/^sequenceDiagram\b/.test(mermaidRoot)) {
    addIssue(`${label} requires a sequenceDiagram but received a different diagram type.`);
  }

  if (requiredDiagram === 'graph LR' && hasDiagram && !/^(graph|flowchart)\s+LR\b/.test(mermaidRoot)) {
    addIssue(`${label} requires a graph LR diagram but received a different diagram type.`);
  }

  if (isTcpFillInPrompt(promptText) && diagramRevealsSeqAck(question.diagram)) {
    addIssue(`${label} still reveals Seq/Ack values after auto-sanitization.`);
  }

  if (
    diagramFamily === 'graph' &&
    isSymmetricTopologyPrompt(promptText) &&
    hasDiagram &&
    !isSymmetricDiagram(question.diagram)
  ) {
    addIssue(`${label} describes a symmetric topology but the Mermaid diagram is still not symmetric after auto-sanitization.`);
  }

  if (questionFormat === 'table') {
    if (!isValidTableData(question.tableData)) {
      addIssue(`${label} requires tableData because the blueprint questionFormat is "table".`);
    } else {
      const hasLeakInTable =
        question.tableData.columns.some((col) => containsAnswerLeak(String(col || ''))) ||
        question.tableData.rows.some((row) =>
          Array.isArray(row) &&
          row.some((cell) => containsAnswerLeak(String(cell || '')))
        );

      if (hasLeakInTable) {
        addIssue(`${label} tableData appears to reveal the answer.`);
      }
    }
  }

  if (!isNonEmptyString(question.model_answer)) {
    addIssue(`${label} is missing model_answer.`);
  }

  const totalSubPartMarks = Array.isArray(question.sub_parts)
    ? question.sub_parts.reduce((sum, part) => sum + (Number(part.marks) || 0), 0)
    : 0;

  if (typeof question.marks !== 'number' || question.marks <= 0) {
    addIssue(`${label} must have a positive numeric marks value.`);
  } else if (totalSubPartMarks !== question.marks) {
    addIssue(`${label} total sub-part marks (${totalSubPartMarks}) do not equal question marks (${question.marks}).`);
  }
});

if (issues.length > 0) {
