const longForm = Array.isArray(exam.longForm) ? exam.longForm : [];

function isNonEmptyString(value) {
  return typeof value === 'string' && value.trim().length > 0;
}

function normalizeGraphLabel(text) {
  return String(text ?? '')
    .replace(/<br\s*\/?>/gi, ' / ')
    .replace(/"/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeSequenceText(text) {
  return String(text ?? '')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function getDiagramType(firstLine) {
  if (!isNonEmptyString(firstLine)) return 'unknown';
  if (firstLine.startsWith('graph')) return 'graph';
  if (firstLine.startsWith('flowchart')) return 'flowchart';
  if (firstLine === 'sequenceDiagram') return 'sequenceDiagram';
  if (firstLine.startsWith('classDiagram')) return 'classDiagram';
  if (firstLine.startsWith('stateDiagram')) return 'stateDiagram';
  return 'unknown';
}

function cleanMermaid(code) {
  if (!isNonEmptyString(code)) return '';

  let cleaned = code.trim();
  cleaned = cleaned.replace(/^```(?:mermaid)?\s*/i, '');
  cleaned = cleaned.replace(/\s*```$/i, '');
  cleaned = cleaned.replace(/\u00A0/g, ' ');

  const match = cleaned.match(
    /(graph\s+(?:LR|RL|TB|TD|BT)|flowchart\s+(?:LR|RL|TB|TD|BT)|sequenceDiagram|classDiagram|stateDiagram(?:-v2)?)/,
  );

  if (match) {
    cleaned = cleaned.substring(match.index);
  } else {
    return '';
  }

  const lines = cleaned
    .split('\n')
    .map((line) => line.trimEnd())
    .filter((line) => line.trim().length > 0);

  if (!lines.length) return '';

  const firstLine = lines[0];

  if (firstLine.startsWith('graph') || firstLine.startsWith('flowchart')) {
    for (let i = 1; i < lines.length; i++) {
      lines[i] = lines[i]
        .replace(/\["([^"]+)"\]/g, (_m, label) => `["${normalizeGraphLabel(label)}"]`)
        .replace(/\[([^"\]]+)\]/g, (_m, label) => `["${normalizeGraphLabel(label)}"]`)
        .replace(/--\s*"([^"]+)"\s*-->/g, (_m, label) => ` -->|"${normalizeGraphLabel(label)}"| `)
        .replace(/---\s*"([^"]+)"\s*---/g, (_m, label) => ` ---|"${normalizeGraphLabel(label)}"| `)
        .replace(/==\s*"([^"]+)"\s*==>/g, (_m, label) => ` ==>|"${normalizeGraphLabel(label)}"| `)
        .replace(/\|([^|]+)\|/g, (_m, label) => {
          const unwrapped = String(label).trim().replace(/^"(.*)"$/, '$1');
          return `|"${normalizeGraphLabel(unwrapped)}"|`;
        })
        .replace(/([A-Za-z])-(\d)/g, '$1$2')
        .replace(/\s{2,}/g, ' ')
        .trimEnd();
    }
  }

  if (firstLine === 'sequenceDiagram') {
    for (let i = 1; i < lines.length; i++) {
      lines[i] = lines[i]
        .replace(
          /^(\s*participant\s+)([A-Za-z][A-Za-z0-9_]*)(\s+as\s+)(.+)$/i,
          (_m, prefix, id, asPart, label) =>
            `${prefix}${id}${asPart}${normalizeSequenceText(label)}`,
        )
        .replace(
          /^(\s*participant\s+)([A-Za-z][A-Za-z0-9_]*)(\s*)$/i,
          (_m, prefix, id) => `${prefix}${id}`,
        )
        .trimEnd();
    }
  }

  return lines.join('\n').trim();
}

function buildFallbackTextDiagram(cleanedDiagram) {
  if (!isNonEmptyString(cleanedDiagram)) return null;
  return `Diagram source:\n${cleanedDiagram}`;
}

function buildMermaidInkSvgUrl(mermaidCode) {
  const encoded = Buffer.from(mermaidCode, 'utf-8').toString('base64url');
  return `https://mermaid.ink/svg/${encoded}?theme=neutral&bgColor=!white`;
}

const jobs = [];

longForm.forEach((question, index) => {
  if (!isNonEmptyString(question.diagram)) return;

  const cleaned = cleanMermaid(question.diagram);
  if (!cleaned) return;

  jobs.push({
    json: {
      questionIndex: index,
      questionNumber: question.number,
      diagramType: getDiagramType(cleaned.split('\n')[0]),
      diagramSource: cleaned,
      diagramFallbackText: buildFallbackTextDiagram(cleaned),
      diagramRenderUrl: buildMermaidInkSvgUrl(cleaned),
    },
  });
});

if (!jobs.length) {
  return [{ json: { noDiagramJobs: true } }];
}

return jobs;

