parameters.jsCode:
// Parse Request (Code Node) - CORRECTED
const raw = $input.first()?.json ?? {};

// Normalize body - handle both string and object formats
let body = raw;
if (raw.body) {
  if (typeof raw.body === 'string') {
    try {
      body = JSON.parse(raw.body);
    } catch (e) {
      body = raw.body;
    }
  } else if (typeof raw.body === 'object') {
    body = raw.body;
  }
}

// Extract message/query
const message = body.message || body.query || body.chatInput || '';
const conversationId = body.conversationId || body.sessionId || '';
const isSlideChat = Boolean(body.isSlideChat);

// CRITICAL FIX: Properly extract nested slideContext object
const slideContext = body.slideContext || {};

return [{
  json: {
    query: message,
    sessionId: conversationId,
    isSlideChat,
    // Pass the full slideContext object for next node
    slideContext: {
      lessonId: slideContext.lessonId || '',
      lessonTitle: slideContext.lessonTitle || '',
      slideNumber: slideContext.slideNumber || 0,
      lectureId: slideContext.lectureId || '',
      currentExplanation: slideContext.currentExplanation || '',
    }
  }
}];

const input = $input.first().json;

// Clean the answer: 
// 1. Remove DeepSeek's <think> tags so the user doesn't see the internal reasoning
// 2. Trim extra whitespace
let cleanAnswer = String(input.answer || '')
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .trim();

const materials = input.retrieved_materials || [];

// Return the clean answer without forcing any "[General Knowledge]" labels
return [{
  json: {
    answer: cleanAnswer,
    retrieved_materials: materials
  }
}];

const agentOutput = $input.first().json;
const steps = agentOutput.intermediateSteps || agentOutput.steps || [];
const retrieved_materials = [];

// Dedupe: normalize content so "same text" from different tool calls counts as one
function normalizeForDedupe(str) {
  return String(str || '')
    .trim()
    .replace(/\s+/g, ' ');
}

const seenContent = new Set();
const seenSources = new Set();

// One citation per (source, slide) - keeps at most one chunk per slide
const ONE_CITATION_PER_SLIDE = true;

function asNum(x) {
  if (x === undefined || x === null || x === '') return null;
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

for (const step of steps) {
  const toolName = (step.action?.tool || step.action?.name || '').toLowerCase();
  if (!toolName.includes('lecture') && !toolName.includes('textbook')) continue;

  try {
    const raw = typeof step.observation === 'string' ? JSON.parse(step.observation) : step.observation;
    const results = Array.isArray(raw) ? raw : [raw];

    for (const r of results) {
      if (!r) continue;

      let content = r.pageContent ?? r.content ?? r.text ?? '';
      let metaFromInner = null;

      if (typeof content === 'string' && content.trim().startsWith('{')) {
        try {
          const inner = JSON.parse(content);
          content = inner.pageContent || inner.text || inner.content || content;
          if (inner.metadata) metaFromInner = inner.metadata;
        } catch (_) {}
      }

      const cleanContent = String(content).trim();
      if (cleanContent.length < 20) continue;

      const normalizedContent = normalizeForDedupe(cleanContent);
      if (seenContent.has(normalizedContent)) continue;
      seenContent.add(normalizedContent);

      const meta0 = metaFromInner || r.metadata || {};
      const meta = meta0.metadata || meta0 || {};

      const source_type = toolName.includes('textbook') ? 'Textbook' : 'Lecture Slides';
      const lecture_id = meta.lecture_id ?? null;
      const lecture_title = meta.lecture_title ?? null;
      const slide_number = asNum(meta.slide_number);
      const page_number = asNum(meta.page_number);

      const sourceKey = `${lecture_id || lecture_title || ''}|${slide_number ?? page_number ?? ''}`;
      if (ONE_CITATION_PER_SLIDE && seenSources.has(sourceKey)) continue;
      if (ONE_CITATION_PER_SLIDE) seenSources.add(sourceKey);

      const document_title = meta.document_title ?? lecture_title ?? meta.filename ?? null;

      retrieved_materials.push({
        source_type,
        lecture_id,
        lecture_title,
        slide_number,
        page_number,
        document_title,
        content: cleanContent,
        excerpt: cleanContent,
      });
    }
  } catch (e) {
    console.log('Extract skip:', e.message);
  }
}

// Final dedupe pass: same (document, slide/page, normalized content) => keep one
const seenKey = new Set();
const deduped = retrieved_materials.filter((m) => {
  const key = [
    m.document_title ?? m.lecture_title ?? '',
    m.slide_number ?? '',
    m.page_number ?? '',
    normalizeForDedupe(m.content || ''),
  ].join('|');
  if (seenKey.has(key)) return false;
  seenKey.add(key);
  return true;
});

const answer = agentOutput.output || agentOutput.text || '';
const cleanAnswer = String(answer).trim();

return [
  {
    json: {
      answer: cleanAnswer,
      retrieved_materials: deduped,
    },
  },
];

const raw = $input.first().json;
const body = typeof raw.body === 'string' ? JSON.parse(raw.body) : (raw.body || raw);

function pick(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

function shuffle(arr) {
  const copy = [...arr];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy;
}

function clamp(value, min, max) {
  return Math.min(Math.max(value, min), max);
}

const mode = body.mode === 'quick_practice' ? 'quick_practice' : 'exam_simulation';
const topic = typeof body.topic === 'string' && body.topic.trim() ? body.topic.trim() : 'Computer Networks';
const difficulty = ['easy', 'medium', 'hard'].includes(body.difficulty) ? body.difficulty : 'medium';
const includeTopics = Array.isArray(body.includeTopics) ? body.includeTopics.filter(Boolean) : [];
const excludeTopics = Array.isArray(body.excludeTopics) ? body.excludeTopics.filter(Boolean) : [];
const studentWeaknesses = Array.isArray(body.studentWeaknesses) ? body.studentWeaknesses : [];
const sessionId =
  typeof body.sessionId === 'string' && body.sessionId.trim()
    ? body.sessionId.trim()
    : `exam-${Date.now()}`;

const requestedNumMCQ = Number.parseInt(body.numMultipleChoice, 10);
const requestedNumOpenEnded = Number.parseInt(body.numOpenEnded, 10);

const difficultyAnchors = {
  easy: 'Homework 1-2 / direct recall and one-step application',
  medium: 'Homework 3-4 / multi-step application',
  hard: 'Midterm Sections E-F / chained reasoning and diagram-heavy analysis',
};

const difficultyProfiles = {
  easy: {
    minSubParts: 3,
    targetSubParts: 4,
    maxSubParts: 4,
    minDiagramRatio: 0.5,
    minDiagramCount: 2,
    defaultOpenEnded: 3,
    preferredSources: ['homework', 'past_paper'],
  },
  medium: {
    minSubParts: 4,
    targetSubParts: 4,
    maxSubParts: 5,
    minDiagramRatio: 0.6,
    minDiagramCount: 2,
    defaultOpenEnded: 5,
    preferredSources: ['midterm', 'homework'],
  },
  hard: {
    minSubParts: 4,
    targetSubParts: 5,
    maxSubParts: 6,
    minDiagramRatio: 0.7,
    minDiagramCount: 3,
    defaultOpenEnded: 5,
    preferredSources: ['midterm_recent', 'midterm', 'homework'],
  },
};

const difficultyStructure = {
  difficulty,
  difficultyAnchor: difficultyAnchors[difficulty],
  ...(difficultyProfiles[difficulty] || difficultyProfiles.medium),
};

const numMultipleChoice = mode === 'quick_practice'
  ? (Number.isFinite(requestedNumMCQ) ? clamp(requestedNumMCQ, 5, 15) : 10)
  : (Number.isFinite(requestedNumMCQ) ? clamp(requestedNumMCQ, 0, 15) : 10);

const numOpenEnded = mode === 'quick_practice'
  ? 0
  : (Number.isFinite(requestedNumOpenEnded)
      ? clamp(requestedNumOpenEnded, 3, 7)
      : difficultyStructure.defaultOpenEnded);

const archetypes = [
  {
    category: 'HTTP / Web Scenario',
    focusTopics: [
      'HTTP/1.0 vs HTTP/1.1',
      'Persistent vs non-persistent HTTP',
      'Web objects and TCP connections',
      'Connection setup and RTT reasoning',
    ],
    requiredDiagram: 'none',
    questionFormat: 'text',
    diagramInstructions: 'No diagram needed. Focus on scenario-based reasoning and progressive sub-parts.',
    sourceExamType: 'midterm',
    sourcePeriod: difficulty === 'hard' ? 'midterm recent' : 'homework + past paper',
    supportsTopics: ['HTTP', 'Web', 'Transport', 'Application Layer'],
  },
  {
    category: 'Video Streaming / DASH',
    focusTopics: [
      'Adaptive bitrate streaming',
      'Manifest files and segment switching',
      'Buffer-aware streaming decisions',
      'Rate adaptation logic',
    ],
    requiredDiagram: 'none',
    questionFormat: 'text',
    diagramInstructions: 'No diagram needed. Focus on calculation plus reasoning about player behavior.',
    sourceExamType: 'homework',
    sourcePeriod: 'homework + past paper',
    supportsTopics: ['DASH', 'Streaming', 'Application Layer'],
  },
  {
    category: 'TCP Header / Seq-Ack Fill-In',
    focusTopics: [
      'TCP sequence numbers',
      'TCP acknowledgment numbers',
      '3-way handshake and data transfer',
      'Seq/Ack ladder reasoning',
    ],
    requiredDiagram: 'sequenceDiagram',
    questionFormat: 'table',
    diagramInstructions: 'Write valid Mermaid sequenceDiagram code showing a TCP exchange with single-word participant names. Use Seq=? and Ack=? placeholders in student-facing diagrams when values are to be derived.',
    sourceExamType: 'midterm',
    sourcePeriod: difficulty === 'hard' ? 'midterm recent' : 'midterm + homework',
    supportsTopics: ['TCP', 'Transport', 'Seq/Ack'],
  },

  {
    category: 'Network Performance Analysis',
    focusTopics: [
      'Transmission delay',
      'Propagation delay',
      'Store-and-forward delay',
      'Queue buildup and overflow',
      'Throughput vs bottleneck reasoning',
    ],
    requiredDiagram: 'graph LR',
    questionFormat: 'text',
    diagramInstructions: 'Write valid Mermaid graph LR code with quoted node labels and quoted edge labels that include link rate and delay.',
    sourceExamType: 'midterm',
    sourcePeriod: difficulty === 'hard' ? 'midterm recent' : 'midterm + homework',
    supportsTopics: ['Delay', 'Throughput', 'Queueing', 'Performance'],
  },
  {
    category: 'Transport Reliability / Sliding Window',
    focusTopics: [
      'Go-Back-N',
      'Selective Repeat',
      'Sender and receiver window state',
      'Timeout and retransmission reasoning',
    ],
    requiredDiagram: 'sequenceDiagram',
    questionFormat: 'text',
    diagramInstructions: 'Write valid Mermaid sequenceDiagram code that helps trace sender and receiver behaviour across time.',
    sourceExamType: 'midterm',
    sourcePeriod: difficulty === 'hard' ? 'midterm recent' : 'midterm + homework',
    supportsTopics: ['GBN', 'Selective Repeat', 'Sliding Window', 'Transport'],
  },
  {
    category: 'Routing / Topology Analysis',
    focusTopics: [
      'Dijkstra shortest path',
      'Distance Vector',
      'Count-to-infinity',
      'Spanning Tree Protocol',
      'NAT translation logic',
    ],
    requiredDiagram: 'graph LR',
    questionFormat: 'text',
    diagramInstructions: 'Write valid Mermaid graph LR code using single-word node IDs and quoted edge labels.',
    sourceExamType: 'homework',
    sourcePeriod: 'homework + past paper',
    supportsTopics: ['Routing', 'Topology', 'NAT', 'Network Layer'],
  },
];

function archetypeMatchesFilters(archetype) {
  const searchable = [
    archetype.category,
    ...archetype.focusTopics,
    ...(archetype.supportsTopics || []),
  ].join(' ').toLowerCase();

  const hasIncludedTopic =
    includeTopics.length === 0 ||
    includeTopics.some((topic) => searchable.includes(String(topic).toLowerCase()));

  const hasExcludedTopic =
    excludeTopics.length > 0 &&
    excludeTopics.some((topic) => searchable.includes(String(topic).toLowerCase()));

  return hasIncludedTopic && !hasExcludedTopic;
}

const eligibleArchetypes = archetypes.filter(archetypeMatchesFilters);
const archetypePool = eligibleArchetypes.length > 0 ? eligibleArchetypes : archetypes;

const diagramArchetypes = archetypePool.filter((item) => item.requiredDiagram !== 'none');
const nonDiagramArchetypes = archetypePool.filter((item) => item.requiredDiagram === 'none');

const blueprint = [];

if (mode === 'exam_simulation' && numOpenEnded > 0) {
  const minDiagramCount = Math.min(
    numOpenEnded,
    Math.max(
      difficultyStructure.minDiagramCount,
      Math.ceil(numOpenEnded * difficultyStructure.minDiagramRatio),
    ),
  );

  const diagramFirstPool = shuffle(diagramArchetypes);
  const otherPool = shuffle(nonDiagramArchetypes);

  const selectedArchetypes = [];

  for (let i = 0; i < minDiagramCount && diagramFirstPool.length > 0; i++) {
    selectedArchetypes.push(diagramFirstPool[i % diagramFirstPool.length]);
  }

  const fillPool = shuffle([
    ...diagramFirstPool.slice(minDiagramCount),
    ...otherPool,
    ...archetypePool,
  ]);

  while (selectedArchetypes.length < numOpenEnded && fillPool.length > 0) {
    selectedArchetypes.push(fillPool[(selectedArchetypes.length - minDiagramCount) % fillPool.length]);
  }

  while (selectedArchetypes.length < numOpenEnded) {
    selectedArchetypes.push(archetypePool[selectedArchetypes.length % archetypePool.length]);
  }

  selectedArchetypes.forEach((archetype, i) => {
    const focusTopic = pick(archetype.focusTopics);

    blueprint.push({
      questionNumber: numMultipleChoice + 1 + i,
      category: archetype.category,
      focusTopic,
