const raw = $input.first().json;
let output = raw.output || raw.text || raw.response || raw.content || raw.body || '';

// Handle case where input is already an object
if (typeof output === 'object') {
  output = JSON.stringify(output);
}

// Remove <think> tags and markdown fences
output = output.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
output = output.replace(/```json/gi, '').replace(/```/g, '').trim();

// Find the JSON object
const firstOpen = output.indexOf('{');
const lastClose = output.lastIndexOf('}');

if (firstOpen !== -1 && lastClose !== -1) {
  output = output.substring(firstOpen, lastClose + 1);
} else {
  if (raw.mcqs || raw.longForm || raw.metadata) {
    return formatOutput(raw, raw);
  }
  throw new Error(`No JSON brackets found. Preview: ${output.substring(0, 100)}...`);
}

function robustRepair(jsonStr) {
  let inString = false;
  let isEscaped = false;
  let result = '';

  for (let i = 0; i < jsonStr.length; i++) {
    const char = jsonStr[i];

    if (inString) {
      if (isEscaped) {
        result += char;
        isEscaped = false;
      } else {
        if (char === '\\') {
          result += char;
          isEscaped = true;
        } else if (char === '"') {
          inString = false;
          result += char;
        } else if (char === '\n') {
          result += '\\n';
        } else if (char === '\r') {
          // drop carriage returns inside strings
        } else if (char === '\t') {
          result += '\\t';
        } else {
          result += char;
        }
      }
    } else {
      if (char === '"') {
        inString = true;
      }
      result += char;
    }
  }

  return result
    .replace(/,\s*([\]}])/g, '$1')
    .replace(/}\s*{/g, '},{');
}

let examData;
try {
  examData = JSON.parse(output);
} catch (e1) {
  try {
    const repaired = robustRepair(output);
    examData = JSON.parse(repaired);
  } catch (e2) {
    throw new Error(
      `CRITICAL PARSE FAILURE.\nThis is likely very bad output from the LLM.\nError: ${e2.message}\nStart of content: ${output.substring(0, 500)}`
    );
  }
}

return formatOutput(examData, raw);

function formatOutput(data, originalContext) {
  const mcqs = Array.isArray(data.mcqs) ? data.mcqs : [];
  const longForm = Array.isArray(data.longForm) ? data.longForm : [];

  let req = {};
  try {
    req = $('Parse Request').first().json;
  } catch (e) {
    req = originalContext.metadata || {};
  }

  const modelMetadata =
    data && typeof data.metadata === 'object' && data.metadata !== null
      ? data.metadata
      : {};

  return [
    {
      json: {
        mcqs,
        longForm,
        metadata: {
          ...modelMetadata,
          topic: req.topic || modelMetadata.topic || 'Unknown',
          difficulty: req.difficulty || modelMetadata.difficulty,
          difficultyAnchor: req.difficultyAnchor || modelMetadata.difficultyAnchor,
          variation: req.variation || modelMetadata.variation || {},
          mode: req.mode || modelMetadata.mode,
          sessionId: req.sessionId || modelMetadata.sessionId,
          numMC: mcqs.length,
          numOE: longForm.length,
        },
      },
    },
  ];
}

