});

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function formatOptionForDisplay(option, index) {
  const trimmed = String(option ?? '').trim();
  if (/^[A-Z][).:]\s/.test(trimmed)) {
    return trimmed;
  }
  return `${String.fromCharCode(65 + index)}) ${trimmed}`;
}

function sanitizeInlineSvg(svg) {
  if (typeof svg !== 'string') return null;

  const trimmed = svg
    .trim()
    .replace(/<\?xml[\s\S]*?\?>/i, '')
    .replace(/<style[^>]*>\s*@import[\s\S]*?<\/style>/gi, '')
    .replace(/@import\s+url\([^)]+\);?/gi, '')
    .trim();

  return trimmed.startsWith('<svg') ? trimmed : null;
}

function renderTable(tableData) {
  if (!tableData || !Array.isArray(tableData.columns) || !Array.isArray(tableData.rows)) {
    return '';
  }

  const headerRow = tableData.columns
    .map((column) => `<th>${escapeHtml(column)}</th>`)
    .join('');

  const bodyRows = tableData.rows
    .map((row) => {
      const cells = Array.isArray(row) ? row : [];
      return `<tr>${cells
        .map((cell) =>
          cell === ''
            ? '<td class="blank">&nbsp;</td>'
            : `<td>${escapeHtml(cell)}</td>`
        )
        .join('')}</tr>`;
    })
    .join('');

  return `<table class="q-table"><thead><tr>${headerRow}</tr></thead><tbody>${bodyRows}</tbody></table>`;
}

function renderMcqQuestion(q) {
  return `
    <div class="question">
      <div class="q-head">
        <span class="q-num">Question ${Number(q.number) || ''}</span>
        <span class="marks">[${Number(q.marks) || 2} marks]</span>
      </div>
      <p>${escapeHtml(q.question)}</p>
      <div class="options">
        ${(Array.isArray(q.options) ? q.options : [])
          .map((option, index) => `<div class="opt">${escapeHtml(formatOptionForDisplay(option, index))}</div>`)
          .join('')}
      </div>
    </div>`;
}

function renderLongFormQuestion(q) {
  const inlineSvg = sanitizeInlineSvg(q.diagramSvg);

  const fallbackHtml = q.diagramFallbackText
    ? `<div class="diagram-fallback" style="padding:12px;border:1px dashed #999;background:#f9f9f9;font-family:monospace;font-size:9pt;white-space:pre-wrap;margin:10px 0;">${escapeHtml(q.diagramFallbackText)}</div>`
    : '<div style="padding:8px;color:#999;font-style:italic;">[No diagram available for this question]</div>';

  const diagram = inlineSvg
    ? `<div class="diagram-container">
         <div class="diagram-svg">${inlineSvg}</div>
         <div class="diagram-caption">Figure for Question ${Number(q.number) || ''}</div>
       </div>`
    : (typeof q.diagramDataUri === 'string' && q.diagramDataUri.startsWith('data:image/')
        ? `<div class="diagram-container">
             <img src="${q.diagramDataUri}" alt="Diagram for Question ${Number(q.number) || ''}" />
             <div class="diagram-caption">Figure for Question ${Number(q.number) || ''}</div>
           </div>`
        : (q.diagramFallbackText ? fallbackHtml : ''));

  const parts = (Array.isArray(q.sub_parts) ? q.sub_parts : []).map((sp) => `
    <div class="sub">
      <span class="sub-l">(${escapeHtml(sp.label)})</span>
      <span class="sub-t">${escapeHtml(sp.text)}</span>
      <span class="marks">[${Number(sp.marks) || 0} marks]</span>
    </div>
  `).join('');

  return `
    <div class="question">
      <div class="q-head">
        <span class="q-num">Question ${Number(q.number) || ''}</span>
        <span class="marks">[${Number(q.marks) || 0} marks]</span>
      </div>
      <p>${escapeHtml(q.question)}</p>
      ${diagram}
      ${q.tableData ? renderTable(q.tableData) : ''}
      ${parts}
      <div class="ans-space"></div>
    </div>`;
}

