}

function isSymmetricTopologyPrompt(text) {
  return /symmetric topology|bidirectional links?|links in both directions|undirected topology|two-way links?/i.test(text || '');
}

function normalizeSymmetricLinks(diagram) {
  if (!isNonEmptyString(diagram)) return diagram;
  return diagram
    .replace(/-->/g, '---')
    .replace(/==>/g, '===')
    .replace(/-\.->/g, '-.-');
}

function hasUndirectedLinks(diagram) {
  return /---|===|-\.-/.test(diagram || '');
}

function getDirectedPairs(diagram) {
  const pairs = [];

  for (const line of String(diagram || '').split('\n')) {
    const match = line.match(/([A-Za-z0-9_]+).*?(-->|==>|-\.->).*?([A-Za-z0-9_]+)/);
    if (match) {
      pairs.push([match[1], match[3]]);
    }
  }

  return pairs;
}

function isSymmetricDiagram(diagram) {
  if (!isNonEmptyString(diagram)) return false;
  if (hasUndirectedLinks(diagram)) return true;

  const pairs = getDirectedPairs(diagram);
  if (pairs.length === 0) return false;

  const pairSet = new Set(pairs.map(([from, to]) => `${from}->${to}`));
  return pairs.every(([from, to]) => pairSet.has(`${to}->${from}`));
}

