  }

  if (requiredDiagram === 'graph LR' && hasDiagram && !/^(graph|flowchart)\s+LR\b/.test(mermaidRoot)) {
    addIssue(`${label} requires a graph LR diagram but received a different diagram type.`);
  }

  if (isTcpFillInPrompt(promptText) && diagramRevealsSeqAck(question.diagram)) {
