  if (!/stop-and-wait|stop and wait/i.test(prompt)) return false;
  if (!/^sequenceDiagram\b/.test(String(diagram).trim())) return false;

  const lines = String(diagram)
    .split('\n')
    .map((line) => line.trim())
    .filter(Boolean);

  let outstandingDataMessages = 0;

  for (const line of lines) {
    const match = line.match(/^[A-Za-z0-9_]+[-=.]+>?[A-Za-z0-9_]+:\s*(.+)$/);
    if (!match) continue;

    const message = match[1].trim().toLowerCase();

    if (/\back\b/.test(message) && !/\bdata\b/.test(message)) {
      outstandingDataMessages = 0;
      continue;
    }

    if (/\bdata\b|\bseg(?:ment)?\b|\bpkt\b|\bpacket\b|\bpayload\b/.test(message) && !/\back\b/.test(message)) {
      outstandingDataMessages += 1;
      if (outstandingDataMessages > 1) {
        return true;
      }
    }
  }

  return false;
}

function hasImpossibleQueueBuildup(question) {
  const prompt = extractPrompt(question);

  if (!/queue buildup|queue build-up|queue build up|queue overflow|router overflow|buffer overflow|rate of queue buildup/i.test(prompt)) {
    return false;
  }

  const link1Mbps = extractLinkBandwidthMbps(prompt, 1);
  const link2Mbps = extractLinkBandwidthMbps(prompt, 2);

  if (link1Mbps == null || link2Mbps == null) {
    return false;
  }

  return link2Mbps > link1Mbps;
}

const issues = [];

longForm.forEach((question, index) => {
  const blueprintItem = blueprint[index] || null;
  const requiredDiagram = blueprintItem?.requiredDiagram || 'none';
  const prompt = extractPrompt(question);
  const diagram = question.diagram || '';
  const label = `Question ${question.number || index + 1}`;

  if (requiredDiagram !== 'none' && !looksLikeMermaidDiagram(diagram)) {
    issues.push({
      severity: 'critical',
      code: 'non_renderable_required_diagram',
      questionNumber: question.number || index + 1,
      message: `${label} requires a diagram, but the diagram is plain text or invalid Mermaid.`,
    });
  }

  if (requiredDiagram !== 'none' && !hasRenderableDiagramAsset(question)) {
    const renderDetail =
      typeof question.diagramRenderError === 'string' && question.diagramRenderError.trim()
        ? ` Renderer detail: ${question.diagramRenderError}`
        : '';

    issues.push({
      severity: 'critical',
      code: 'diagram_render_failed',
      questionNumber: question.number || index + 1,
      message: `${label} requires a diagram, but the Mermaid did not render into SVG.${renderDetail}`,
    });
  }

  if (hasStopAndWaitContradiction(question)) {
    issues.push({
      severity: 'critical',
      code: 'stop_and_wait_contradiction',
      questionNumber: question.number || index + 1,
      message: `${label} says stop-and-wait, but the sequence diagram shows multiple data sends before an ACK.`,
    });
  }

  if (hasImpossibleQueueBuildup(question)) {
    issues.push({
      severity: 'critical',
      code: 'impossible_queue_buildup',
      questionNumber: question.number || index + 1,
      message: `${label} asks about queue buildup or overflow, but the stated link rates make buildup impossible.`,
    });
  }
});

payload.metadata = {
  ...(payload.metadata || {}),
  qualityAudit: {
    checkedAt: new Date().toISOString(),
    issueCount: issues.length,
    criticalIssueCount: issues.filter((issue) => issue.severity === 'critical').length,
    issues,
  },
};

return [{ json: payload }];

const exam = $input.first().json;
const req = $('Parse Request').first().json;

const qualityWarnings = (exam.metadata?.qualityAudit?.issues || []).map((issue) => issue.message);
const exportWarnings = exam.metadata?.exportAudit?.exportBlockingIssues || [];

return [{
  json: {
    success: false,
    requiresReview: true,
    sessionId: req.sessionId,
    mode: req.mode,
    exam: {
      mcqs: exam.mcqs || [],
      longForm: exam.longForm || [],
      metadata: {
        ...(exam.metadata || {}),
        mode: req.mode,
        topic: req.topic,
        difficulty: req.difficulty,
        difficultyAnchor: req.difficultyAnchor,
        sessionId: req.sessionId,
      },
    },
    pdf: null,
    warnings: [...qualityWarnings, ...exportWarnings],
  },
}];

const exam = $input.first().json;
const req = $('Parse Request').first().json;

const longForm = Array.isArray(exam.longForm) ? exam.longForm : [];
const blueprint = Array.isArray(req.variation?.blueprint) ? req.variation.blueprint : [];
const issues = Array.isArray(exam.metadata?.qualityAudit?.issues) ? exam.metadata.qualityAudit.issues : [];

const flaggedQuestionNumbers = [...new Set(
  issues
    .filter((issue) => issue?.severity === 'critical')
    .map((issue) => Number(issue.questionNumber))
    .filter((value) => Number.isFinite(value))
)];

const flaggedQuestions = longForm
  .filter((question) => flaggedQuestionNumbers.includes(Number(question.number)))
  .map((question) => {
    const blueprintItem = blueprint.find((item) => Number(item.questionNumber) === Number(question.number)) || null;
    const questionIssues = issues
      .filter((issue) => Number(issue.questionNumber) === Number(question.number))
      .map((issue) => issue.message);

    return {
      questionNumber: question.number,
      originalQuestion: question,
      blueprintItem,
      issues: questionIssues,
    };
  });

return [{
  json: {
    exam,
    repairAttemptCount: Number(exam.metadata?.repairAttemptCount || 0),
    flaggedQuestions,
  },
}];

const raw = $input.first().json;
let output = raw.output || raw.text || raw.response || raw.content || raw.body || '';

if (typeof output === 'object') {
  output = JSON.stringify(output);
}

output = output.replace(/```json/gi, '').replace(/```/g, '').trim();

const firstOpen = output.indexOf('[');
const lastClose = output.lastIndexOf(']');

if (firstOpen === -1 || lastClose === -1) {
  throw new Error(`Repair node did not return a JSON array. Preview: ${String(output).substring(0, 200)}`);
}

output = output.substring(firstOpen, lastClose + 1);

let repairedQuestions;

try {
  repairedQuestions = JSON.parse(output);
} catch (error) {
  throw new Error(`Failed to parse repaired questions JSON: ${error.message}`);
}

if (!Array.isArray(repairedQuestions)) {
  throw new Error('Repaired questions payload is not an array.');
}

return [{ json: { repairedQuestions } }];

const exam = $('Prepare Open-Ended Repair Payload').first().json.exam;
const parsed = $input.first().json;

const repairedQuestions = Array.isArray(parsed.repairedQuestions) ? parsed.repairedQuestions : [];
const repairedByNumber = new Map(
  repairedQuestions
    .filter((question) => question && Number.isFinite(Number(question.number)))
    .map((question) => [Number(question.number), question])
);

const longForm = (Array.isArray(exam.longForm) ? exam.longForm : []).map((question) => {
  const repaired = repairedByNumber.get(Number(question.number));
  return repaired ? repaired : question;
});

return [{
  json: {
    ...exam,
    longForm,
    metadata: {
      ...(exam.metadata || {}),
      repairAttemptCount: Number(exam.metadata?.repairAttemptCount || 0) + 1,
      lastRepairAt: new Date().toISOString(),
    },
  },
}];

const payload = $input.first().json;
const req = $('Parse Request').first().json;

const longForm = Array.isArray(payload.longForm) ? payload.longForm : [];
const blueprint = Array.isArray(req.variation?.blueprint) ? req.variation.blueprint : [];

function isNonEmptyString(value) {
  return typeof value === 'string' && value.trim().length > 0;
}

function removeEmptyDiagramReference(questionText, diagram, requiredDiagram) {
  if ((requiredDiagram && requiredDiagram !== 'none' && isNonEmptyString(diagram)) || isNonEmptyString(diagram)) {
    return questionText;
  }

  return String(questionText || '')
    .replace(/\s*Refer to the diagram below\.\s*/gi, ' ')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

function findInlineSubpartMarkerIndex(questionText) {
  const text = String(questionText || '');
  const patterns = [
    /\(\s*[a-zA-Z]\s*\)/m,
    /(?:^|\n)\s*[a-zA-Z][).]\s+/m,
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && typeof match.index === 'number') {
      return match.index;
    }
  }

  return -1;
}

function stripInlineSubparts(questionText) {
  const text = String(questionText || '');
  const markerIndex = findInlineSubpartMarkerIndex(text);

  if (markerIndex === -1) {
    return text.trim();
  }

  return text
    .slice(0, markerIndex)
    .replace(/\s{2,}/g, ' ')
    .trim();
}

const normalizedLongForm = longForm.map((question, index) => {
  const blueprintItem = blueprint[index] || null;
  const requiredDiagram = blueprintItem?.requiredDiagram || 'none';

  let normalizedQuestionText = String(question.question || '').trim();

  normalizedQuestionText = removeEmptyDiagramReference(
    normalizedQuestionText,
    question.diagram,
    requiredDiagram,
  );

  if (Array.isArray(question.sub_parts) && question.sub_parts.length > 0) {
    normalizedQuestionText = stripInlineSubparts(normalizedQuestionText);
  }

  return {
    ...question,
    question: normalizedQuestionText,
  };
});

return [{
  json: {
    ...payload,
    longForm: normalizedLongForm,
  },
}];

const req = $input.first().json;
const blueprint = Array.isArray(req.variation?.blueprint) ? req.variation.blueprint : [];
const includeTopics = Array.isArray(req.includeTopics) ? req.includeTopics : [];
const studentWeaknesses = Array.isArray(req.studentWeaknesses) ? req.studentWeaknesses : [];

function compact(parts) {
  return parts.filter(Boolean).join(' ').replace(/\s{2,}/g, ' ').trim();
}

function makeSearchSentence(parts) {
  return `Represent this sentence for searching relevant passages: ${compact(parts)}`;
}

const jobs = [];

if (Number(req.numMultipleChoice || 0) > 0) {
  jobs.push({
    jobId: 'mcq_bundle',
    jobType: 'mcq_bundle',
    topic: req.topic,
    difficulty: req.difficulty,
    difficultyAnchor: req.difficultyAnchor,
    query: makeSearchSentence([
      'ELEC3120',
      req.topic,
      'MCQ-style questions',
      req.difficultyAnchor,
      'homework past paper concepts',
      includeTopics.join(' '),
      studentWeaknesses.join(' '),
    ]),
    topK: Math.min(Math.max(Number(req.numMultipleChoice) * 3, 10), 20),
  });
}

blueprint.forEach((item, index) => {
  jobs.push({
    jobId: `long_form_${item.questionNumber}`,
    jobType: 'long_form',
    questionNumber: item.questionNumber,
    blueprintIndex: index,
    category: item.category,
    focusTopic: item.focusTopic,
    requiredDiagram: item.requiredDiagram,
    difficultyAnchor: item.difficultyAnchor,
    sourceExamType: item.sourceExamType,
    sourcePeriod: item.sourcePeriod,
    query: makeSearchSentence([
      'ELEC3120',
      item.category,
      item.focusTopic,
      item.requiredDiagram,
      item.difficultyAnchor,
      'professor-style multi-part question',
      includeTopics.join(' '),
      studentWeaknesses.join(' '),
    ]),
    topK: 8,
  });
});

return jobs.map((job) => ({ json: job }));

const req = $('Parse Request').first().json;
const jobs = $('Build Retrieval Jobs').all().map((item) => item.json || {});
const retrievedItems = $input.all();

function getSourceJobIndex(item) {
  if (typeof item.pairedItem === 'number') return item.pairedItem;

  if (item.pairedItem && typeof item.pairedItem.item === 'number') {
    return item.pairedItem.item;
  }

  if (Array.isArray(item.pairedItem) && typeof item.pairedItem[0]?.item === 'number') {
    return item.pairedItem[0].item;
  }

  return null;
}

function normalizeRetrievedRow(itemJson) {
  const document = itemJson?.document || {};
  const metadata =
    document?.metadata && typeof document.metadata === 'object'
      ? document.metadata
      : {};

  const content =
    document?.pageContent ||
    itemJson?.pageContent ||
    itemJson?.content ||
    '';

  return {
    content: String(content || '').trim(),
    metadata,
    score: typeof itemJson?.score === 'number' ? itemJson.score : null,
    raw: itemJson,
  };
}

function dedupeRows(rows) {
  const seen = new Set();
  const deduped = [];

  for (const row of rows) {
    const key = row.content;
    if (!key || seen.has(key)) continue;
    seen.add(key);
    deduped.push(row);
  }

  return deduped;
}

function sortRows(rows) {
  return [...rows].sort((a, b) => (b.score ?? -Infinity) - (a.score ?? -Infinity));
}

function looksLikeMcq(row) {
  return /which of the following|which one is true|fill in the blank/i.test(row.content);
}

function buildGroupedByPairedItem() {
  const grouped = new Map(jobs.map((job) => [job.jobId, []]));
  let assignedCount = 0;

  for (const item of retrievedItems) {
    const sourceIndex = getSourceJobIndex(item);
    if (sourceIndex == null || !jobs[sourceIndex]) continue;

    const job = jobs[sourceIndex];
    const row = normalizeRetrievedRow(item.json || {});
    if (!row.content) continue;

    grouped.get(job.jobId).push(row);
    assignedCount += 1;
  }

  return { grouped, assignedCount };
}

function buildGroupedByChunking() {
  const grouped = new Map(jobs.map((job) => [job.jobId, []]));
  let cursor = 0;

  for (const job of jobs) {
    const expectedCount = Number(job.topK || 8);
    const slice = retrievedItems.slice(cursor, cursor + expectedCount);

    for (const item of slice) {
      const row = normalizeRetrievedRow(item.json || {});
      if (!row.content) continue;
      grouped.get(job.jobId).push(row);
    }

    cursor += expectedCount;
  }

  return grouped;
}

const pairedResult = buildGroupedByPairedItem();
const pairingLooksReliable = pairedResult.assignedCount === retrievedItems.length && pairedResult.assignedCount > 0;

const grouped = pairingLooksReliable
  ? pairedResult.grouped
  : buildGroupedByChunking();

const mcqJob = jobs.find((job) => job.jobType === 'mcq_bundle') || null;

const mcqContext = mcqJob
  ? (() => {
      const rows = sortRows(dedupeRows(grouped.get(mcqJob.jobId) || []));
      const preferredRows = rows.filter(looksLikeMcq);
      return {
        ...mcqJob,
        retrievedDocs: (preferredRows.length ? preferredRows : rows).slice(0, 10),
      };
    })()
  : null;

const longFormContexts = jobs
  .filter((job) => job.jobType === 'long_form')
  .map((job) => {
    const rows = sortRows(dedupeRows(grouped.get(job.jobId) || []));
    const preferredRows = rows.filter((row) => !looksLikeMcq(row));

    return {
      ...job,
      retrievedDocs: (preferredRows.length ? preferredRows : rows).slice(0, 6),
    };
  });

return [{
  json: {
    ...req,
    mcqContext,
    longFormContexts,
    retrievalContextVersion: 'v3',
    retrievalStats: {
      totalRetrievedItems: retrievedItems.length,
      pairingLooksReliable,
      mcqDocCount: mcqContext?.retrievedDocs?.length || 0,
      longFormDocCounts: longFormContexts.map((item) => ({
        questionNumber: item.questionNumber,
        docCount: item.retrievedDocs.length,
      })),
    },
  },
}];

// Minimal post-processing. The v3 system prompt handles structure.
// This node only strips: <think>, inline citations, meta-apologies, whitespace.

const item = $input.first().json;
let answer = String(item.answer || "").trim();
const materials = Array.isArray(item.retrieved_materials) ? item.retrieved_materials : [];

// 1. Strip <think> reasoning blocks
answer = answer.replace(/<think>[\s\S]*?<\/think>/g, "").trim();

// 2. Strip inline citations — the UI shows Sources separately
//    Matches: [Lecture 7, Slide 22], [Lecture 07, Slide 72], [Textbook, p.278], [Textbook p. 278]
answer = answer.replace(
  /\s*\[(?:Lecture\s*\d{1,2}\s*,\s*Slide\s*\d{1,3}|Textbook\s*,?\s*p\.?\s*\d{1,4})\]\s*/gi,
  " "
);
// Also strip stacked citations like [Lecture 7, Slide 33][Lecture 7, Slide 66]
answer = answer.replace(/(\s*\[\s*[^\]]{0,80}\s*\])+/g, (match) => {
  // Only strip if every bracket matches the citation-like pattern
  const brackets = match.match(/\[[^\]]+\]/g) || [];
  const allCitationLike = brackets.every((b) =>
    /Lecture\s*\d|Textbook|Slide\s*\d|p\.?\s*\d/i.test(b)
  );
  return allCitationLike ? " " : match;
});

// 3. Strip meta-apology sentences about retrieval
const metaPatterns = [
  /I couldn['']t find[^.]*\./gi,
  /I could not find[^.]*\./gi,
  /The (?:course )?(?:lecture )?(?:slides|materials|notes) (?:don['']t|do not) (?:cover|mention|include|address)[^.]*\./gi,
  /Based on the (?:retrieved )?(?:course )?(?:context|materials|slides)[^,]*,\s*/gi,
  /According to the (?:slides|textbook|course materials)[^,]*,\s*/gi,
];
for (const re of metaPatterns) {
  answer = answer.replace(re, "");
}

// 4. Clean up whitespace left behind
answer = answer
  .replace(/\r\n/g, "\n")
  .replace(/[ \t]{2,}/g, " ")            // collapse double spaces
  .replace(/\n{3,}/g, "\n\n")
  .replace(/[ \t]+\n/g, "\n")
  .replace(/\n\s*\.\s*/g, ".\n")         // leftover orphan periods from stripped clauses
  .trim();

// 5. Ensure blank line before ## headings
answer = answer.replace(/([^\n])\n(##\s)/g, "$1\n\n$2");

return [
  {
    json: {
      answer,
      retrieved_materials: materials
    }
  }
];

