const exam = $input.first().json;
const req = $('Parse Request').first().json;
const blueprint = Array.isArray(req.variation?.blueprint) ? req.variation.blueprint : [];
const longForm = Array.isArray(exam.longForm) ? exam.longForm : [];
const qualityAudit = exam.metadata?.qualityAudit || {};

if (req.mode !== 'exam_simulation') {
  return [{
    json: {
      ...exam,
      metadata: {
        ...(exam.metadata || {}),
        exportAudit: {
          checkedAt: new Date().toISOString(),
          blockingIssueCount: 0,
          exportBlockingIssues: [],
        },
      },
    },
  }];
}


const exportBlockingIssues = [];

function addBlockingIssue(message) {
  exportBlockingIssues.push(message);
}

function isNonEmptyString(value) {
  return typeof value === 'string' && value.trim().length > 0;
}

function hasRenderableDiagramAsset(question) {
  return (
    isNonEmptyString(question.diagramSvg) ||
    (typeof question.diagramDataUri === 'string' && question.diagramDataUri.startsWith('data:image/'))
  );
}

function hasValidTableData(tableData) {
  return !!(
    tableData &&
    Array.isArray(tableData.columns) &&
    tableData.columns.length > 0 &&
    Array.isArray(tableData.rows) &&
    tableData.rows.length > 0
  );
}

if (Number(qualityAudit.criticalIssueCount || 0) > 0) {
  addBlockingIssue('Critical quality-audit issues remain unresolved.');
}

longForm.forEach((question, index) => {
  const blueprintItem = blueprint[index] || null;
  const requiredDiagram = blueprintItem?.requiredDiagram || 'none';
  const questionFormat = blueprintItem?.questionFormat || 'text';
  const label = `Question ${question.number || index + 1}`;

  if (requiredDiagram !== 'none' && !hasRenderableDiagramAsset(question)) {
    addBlockingIssue(`${label} requires a rendered diagram asset, but neither diagramSvg nor diagramDataUri is available.`);
  }

  if (questionFormat === 'table' && !hasValidTableData(question.tableData)) {
    addBlockingIssue(`${label} requires tableData for export, but tableData is missing or invalid.`);
  }
});

return [{
  json: {
    ...exam,
    metadata: {
      ...(exam.metadata || {}),
      exportAudit: {
        checkedAt: new Date().toISOString(),
        blockingIssueCount: exportBlockingIssues.length,
        exportBlockingIssues,
      },
    },
  },
}];

